const PAGE_SIZE = 20;

export default function BiodataPage() {
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("Semua");
  const [page, setPage] = useState(1);

  const filtered = useMemo(() => {
    return biodataKlien.filter((k) => {
      const matchSearch =
        k.nama.toLowerCase().includes(search.toLowerCase()) ||
        k.provinsi.toLowerCase().includes(search.toLowerCase()) ||
        k.pekerjaan.toLowerCase().includes(search.toLowerCase());
      const matchStatus = filterStatus === "Semua" || k.status === filterStatus;
      return matchSearch && matchStatus;
    });
  }, [search, filterStatus]);

  const totalPages = Math.ceil(filtered.length / PAGE_SIZE);
  const paginated = filtered.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);

  const handleSearch = (val: string) => {
    setSearch(val);
    setPage(1);
  };

  const handleFilter = (val: string) => {
    setFilterStatus(val);
    setPage(1);
  };

  const statusColor: Record<string, string> = {
    Aktif: "bg-blue-100 text-blue-700",
    Selesai: "bg-green-100 text-green-700",
    Relapse: "bg-red-100 text-red-600",
  };

  const total = biodataKlien.length;
  const aktif = biodataKlien.filter((k) => k.status === "Aktif").length;
  const selesai = biodataKlien.filter((k) => k.status === "Selesai").length;

  return (
    <div>
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-800">Biodata Klien</h1>
        <p className="text-sm text-gray-500 mt-1">
          Data identitas klien rehabilitasi BNN Tanah Merah
        </p>
      </div>

      {/* Cards */}
      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-gradient-to-r from-blue-500 to-teal-400 p-5 rounded-xl shadow text-white">
          <p className="text-3xl font-bold">{total}</p>
          <p className="text-sm text-blue-100 mt-1">Total Data Klien</p>
        </div>
        <div className="bg-gradient-to-r from-green-400 to-green-600 p-5 rounded-xl shadow text-white">
          <p className="text-3xl font-bold">{aktif}</p>
          <p className="text-sm text-green-100 mt-1">Klien Aktif</p>
        </div>
        <div className="bg-gradient-to-r from-gray-500 to-gray-700 p-5 rounded-xl shadow text-white">
          <p className="text-3xl font-bold">{selesai}</p>
          <p className="text-sm text-gray-200 mt-1">Klien Selesai</p>
        </div>
      </div>

      {/* Filter & Search */}
      <div className="bg-white p-6 rounded-xl shadow">
        <div className="flex flex-wrap items-center gap-3 mb-4">
          <div className="relative flex-1 min-w-[200px] max-w-sm">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Cari nama, provinsi, pekerjaan..."
              value={search}
              onChange={(e) => handleSearch(e.target.value)}
              className="w-full pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <select
            value={filterStatus}
            onChange={(e) => handleFilter(e.target.value)}
            className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            aria-label="Filter status klien"
          >
            <option>Semua</option>
            <option>Aktif</option>
            <option>Selesai</option>
          </select>
          <span className="text-sm text-gray-500">
            Menampilkan {filtered.length} dari {total} klien
          </span>
        </div>

        {/* Tabel */}
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="bg-blue-600 text-white">
                <th className="px-3 py-3 text-left">No</th>
                <th className="px-3 py-3 text-left">Nama/Inisial</th>
                <th className="px-3 py-3 text-left">JK</th>
                <th className="px-3 py-3 text-left">Umur</th>
                <th className="px-3 py-3 text-left">TTL</th>
                <th className="px-3 py-3 text-left">Pekerjaan</th>
                <th className="px-3 py-3 text-left">Tgl Masuk</th>
                <th className="px-3 py-3 text-left">Tgl Keluar</th>
                <th className="px-3 py-3 text-left">Provinsi</th>
                <th className="px-3 py-3 text-left">Zat</th>
                <th className="px-3 py-3 text-left">Status</th>
              </tr>
            </thead>
            <tbody>
              {paginated.map((item, i) => (
                <tr
                  key={item.id}
                  className={i % 2 === 0 ? "bg-white hover:bg-blue-50" : "bg-gray-50 hover:bg-blue-50"}
                >
                  <td className="px-3 py-2.5 text-gray-500">{(page - 1) * PAGE_SIZE + i + 1}</td>
                  <td className="px-3 py-2.5 font-medium text-gray-800">{item.nama}</td>
                  <td className="px-3 py-2.5">{item.jk}</td>
                  <td className="px-3 py-2.5">{item.umur}</td>
                  <td className="px-3 py-2.5 text-xs text-gray-600">{item.ttl}</td>
                  <td className="px-3 py-2.5 text-xs">{item.pekerjaan}</td>
                  <td className="px-3 py-2.5 text-xs">{item.tgl_masuk}</td>
                  <td className="px-3 py-2.5 text-xs">{item.tgl_keluar || "-"}</td>
                  <td className="px-3 py-2.5 text-xs">{item.provinsi}</td>
                  <td className="px-3 py-2.5 text-xs">{item.zat}</td>
                  <td className="px-3 py-2.5">
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColor[item.status] || "bg-gray-100 text-gray-600"}`}>
                      {item.status}
                    </span>
                  </td>
                </tr>
              ))}
              {paginated.length === 0 && (
                <tr>
                  <td colSpan={11} className="px-4 py-8 text-center text-gray-400">
                    Tidak ada data ditemukan
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between mt-4 text-sm">
            <span className="text-gray-500">
              Halaman {page} dari {totalPages}
            </span>
            <div className="flex gap-2">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page === 1}
                className="flex items-center gap-1 px-3 py-1.5 border rounded-lg disabled:opacity-40 hover:bg-gray-50"
              >
                <ChevronLeft size={14} /> Prev
              </button>
              <button
                onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="flex items-center gap-1 px-3 py-1.5 border rounded-lg disabled:opacity-40 hover:bg-gray-50"
              >
                Next <ChevronRight size={14} />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
